// ConfigurationManager.swift
import Foundation

class ConfigurationManager {
    static let shared = ConfigurationManager()
    
    private init() {}
    
    var googleMapsAPIKey: String? {
        return loadSecret(forKey: "GOOGLE_MAPS_API_KEY")
    }
    
    var stripePublishableKey: String? {
        return loadSecret(forKey: "STRIPE_PUBLISHABLE_KEY")
    }
    
    private func loadSecret(forKey key: String) -> String? {
        // Priority 1: Environment variable
        if let value = ProcessInfo.processInfo.environment[key], !value.isEmpty {
            return value
        }
        
        // Priority 2: Configuration plist (not checked into source control)
        if let path = Bundle.main.path(forResource: "Secrets", ofType: "plist"),
           let dict = NSDictionary(contentsOfFile: path) as? [String: String],
           let value = dict[key], !value.isEmpty {
            return value
        }
        
        // Priority 3: Keychain
        if let value = KeychainManager.shared.retrieve(key: key), !value.isEmpty {
            return value
        }
        
        return nil
    }
}

// KeychainManager.swift
import Foundation
import Security

class KeychainManager {
    static let shared = KeychainManager()
    
    private init() {}
    
    func save(key: String, value: String) -> Bool {
        guard let data = value.data(using: .utf8) else { return false }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        SecItemDelete(query as CFDictionary)
        let status = SecItemAdd(query as CFDictionary, nil)
        return status == errSecSuccess
    }
    
    func retrieve(key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess,
              let data = result as? Data,
              let value = String(data: data, encoding: .utf8) else {
            return nil
        }
        
        return value
    }
    
    func delete(key: String) -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        
        let status = SecItemDelete(query as CFDictionary)
        return status == errSecSuccess
    }
}

// ViewController.swift
import UIKit
import GoogleMaps
import Stripe

class ViewController: UIViewController {
    
    private var mapView: GMSMapView!
    private var payButton: UIButton!
    private var statusLabel: UILabel!
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        setupMap()
    }
    
    private func setupUI() {
        view.backgroundColor = .white
        
        statusLabel = UILabel()
        statusLabel.translatesAutoresizingMaskIntoConstraints = false
        statusLabel.textAlignment = .center
        statusLabel.numberOfLines = 0
        statusLabel.text = "Demo App - Configure API keys to enable features"
        view.addSubview(statusLabel)
        
        payButton = UIButton(type: .system)
        payButton.translatesAutoresizingMaskIntoConstraints = false
        payButton.setTitle("Pay $10.00", for: .normal)
        payButton.backgroundColor = .systemBlue
        payButton.setTitleColor(.white, for: .normal)
        payButton.layer.cornerRadius = 8
        payButton.addTarget(self, action: #selector(payButtonTapped), for: .touchUpInside)
        view.addSubview(payButton)
        
        NSLayoutConstraint.activate([
            statusLabel.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 20),
            statusLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            statusLabel.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            
            payButton.bottomAnchor.constraint(equalTo: view.safeAreaLayoutGuide.bottomAnchor, constant: -20),
            payButton.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            payButton.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            payButton.heightAnchor.constraint(equalToConstant: 50)
        ])
    }
    
    private func setupMap() {
        let camera = GMSCameraPosition.camera(withLatitude: 37.7749, longitude: -122.4194, zoom: 12.0)
        mapView = GMSMapView.map(withFrame: .zero, camera: camera)
        mapView.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(mapView)
        view.sendSubviewToBack(mapView)
        
        NSLayoutConstraint.activate([
            mapView.topAnchor.constraint(equalTo: statusLabel.bottomAnchor, constant: 20),
            mapView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            mapView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            mapView.bottomAnchor.constraint(equalTo: payButton.topAnchor, constant: -20)
        ])
        
        let marker = GMSMarker()
        marker.position = CLLocationCoordinate2D(latitude: 37.7749, longitude: -122.4194)
        marker.title = "San Francisco"
        marker.snippet = "Demo Location"
        marker.map = mapView
    }
    
    @objc private func payButtonTapped() {
        guard ConfigurationManager.shared.stripePublishableKey != nil else {
            showAlert(title: "Configuration Required", message: "Please configure Stripe API key to process payments")
            return
        }
        
        let paymentContext = STPPaymentContext(apiAdapter: PaymentAPIAdapter())
        paymentContext.hostViewController = self
        paymentContext.delegate = self
        paymentContext.paymentAmount = 1000 // $10.00 in cents
        paymentContext.paymentCurrency = "usd"
        
        paymentContext.presentPaymentOptionsViewController()
    }
    
    private func showAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

extension ViewController: STPPaymentContextDelegate {
    func paymentContext(_ paymentContext: STPPaymentContext, didCreatePaymentResult paymentResult: STPPaymentResult, completion: @escaping STPPaymentStatusBlock) {
        statusLabel.text = "Processing payment..."
        
        // In production, send payment to your backend server
        DispatchQueue.main.asyncAfter(deadline: .now() + 2) {
            completion(.success, nil)
        }
    }
    
    func paymentContext(_ paymentContext: STPPaymentContext, didFinishWith status: STPPaymentStatus, error: Error?) {
        switch status {
        case .success:
            statusLabel.text = "Payment successful!"
        case .error:
            statusLabel.text = "Payment failed: \(error?.localizedDescription ?? "Unknown error")"
        case .userCancellation:
            statusLabel.text = "Payment cancelled"
        @unknown default:
            statusLabel.text = "Unknown payment status"
        }
    }
    
    func paymentContextDidChange(_ paymentContext: STPPaymentContext) {
        // Handle payment context changes
    }
}

